/**
 * StudentDashboard — личный кабинет ученика.
 * Виджеты: расписание, записи занятий, остаток уроков, текущий трек, уведомления.
 * Phase 2.1 plan.
 */

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'
import { loadSession } from '../lib/auth'
import { fetchMySlots, type SlotDto } from '../api/schedule'
import { fetchMySubscription, type SubscriptionDto, PACKAGE_LABELS } from '../api/subscriptions'
import { fetchMyNotifications, markNotificationRead, type NotificationDto } from '../api/notifications'

const TRACK_META: Record<string, { label: string; emoji: string; color: string; soft: string }> = {
  python:  { label: 'Python',       emoji: '🐍', color: '#3E87E8', soft: '#DEEBFA' },
  scratch: { label: 'Scratch',      emoji: '🧩', color: '#FF9454', soft: '#FFE2CE' },
  vibe:    { label: 'Vibe-coding',  emoji: '✨', color: '#E8517B', soft: '#FCDDE6' },
}

function formatDateTime(iso: string): string {
  const d = new Date(iso)
  return d.toLocaleString('ru-RU', {
    day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Moscow',
  }) + ' (МСК)'
}

function isLessonAccessible(slot: SlotDto): boolean {
  // Lesson link is active ±10 min around scheduled time + during the slot duration
  const start = new Date(slot.datetime).getTime()
  const end = start + slot.durationMin * 60_000
  const now = Date.now()
  return now >= start - 10 * 60_000 && now <= end + 5 * 60_000
}

export default function StudentDashboard() {
  const session = loadSession()
  const trackKey = (session?.track ?? '').toLowerCase()
  const trackMeta = TRACK_META[trackKey] ?? null

  const [slots, setSlots] = useState<SlotDto[] | null>(null)
  const [sub, setSub] = useState<SubscriptionDto | null>(null)
  const [notifications, setNotifications] = useState<NotificationDto[]>([])
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    fetchMySlots()
      .then(setSlots)
      .catch((e) => setError(e instanceof Error ? e.message : 'Ошибка загрузки'))
  }, [])

  useEffect(() => {
    fetchMySubscription()
      .then((res) => {
        if ('status' in res && res.status === 'none') return
        setSub(res as SubscriptionDto)
      })
      .catch(() => { /* offline-safe */ })
  }, [])

  useEffect(() => {
    fetchMyNotifications()
      .then((items) => setNotifications(items.slice(0, 5)))
      .catch(() => { /* silent */ })
  }, [])

  const upcoming = (slots ?? [])
    .filter((s) => s.status === 'scheduled' && new Date(s.datetime).getTime() > Date.now() - 30 * 60_000)
    .sort((a, b) => new Date(a.datetime).getTime() - new Date(b.datetime).getTime())
    .slice(0, 5)

  const remaining = sub ? Math.max(0, sub.lessonsTotal - sub.lessonsUsed) : null

  return (
    <PlatformShell activeKey="learn">
      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>🎒</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Личный кабинет</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>
              Привет, {session?.name ?? 'ученик'}!
            </h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 960, margin: '0 auto', padding: '28px 16px', display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: 20 }}>

        {/* Виджет: трек */}
        {trackMeta && (
          <div className="kb-card" style={{ padding: 20, background: trackMeta.soft, gridColumn: 'span 1' }}>
            <div className="eyebrow" style={{ color: trackMeta.color }}>Твой трек</div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginTop: 6 }}>
              <span style={{ fontSize: 36 }}>{trackMeta.emoji}</span>
              <div style={{ fontFamily: 'var(--f-display)', fontWeight: 900, fontSize: 22, color: trackMeta.color }}>
                {trackMeta.label}
              </div>
            </div>
            <Link to="/learn" className="kb-btn kb-btn--secondary" style={{ marginTop: 12, fontSize: 13, padding: '6px 14px' }}>
              К урокам →
            </Link>
          </div>
        )}

        {/* Виджет: остаток уроков */}
        <div className="kb-card" style={{ padding: 20 }}>
          <div className="eyebrow">Осталось занятий</div>
          {sub ? (
            <>
              <div style={{ display: 'flex', alignItems: 'baseline', gap: 6, marginTop: 8 }}>
                <div style={{ fontFamily: 'var(--f-display)', fontWeight: 900, fontSize: 36, color: 'var(--ink)' }}>
                  {remaining}
                </div>
                <div style={{ color: 'var(--ink-soft)', fontSize: 14 }}>из {sub.lessonsTotal}</div>
              </div>
              <div style={{ marginTop: 8, fontSize: 13, color: 'var(--ink-soft)' }}>
                Пакет: {PACKAGE_LABELS[sub.plan] ?? sub.plan}
              </div>
              {sub.expiresAt && (
                <div style={{ marginTop: 4, fontSize: 12, color: 'var(--ink-soft)' }}>
                  Действует до {new Date(sub.expiresAt).toLocaleDateString('ru-RU')}
                </div>
              )}
              {remaining !== null && remaining <= 2 && (
                <Link to="/billing" className="kb-btn" style={{ marginTop: 12, fontSize: 13, padding: '6px 14px', background: '#FFD43C', color: '#7A5900' }}>
                  Продлить пакет →
                </Link>
              )}
            </>
          ) : (
            <div style={{ marginTop: 8, color: 'var(--ink-soft)', fontSize: 13 }}>Пакет ещё не назначен.</div>
          )}
        </div>

        {/* Виджет: расписание */}
        <div className="kb-card" style={{ padding: 20, gridColumn: '1 / -1' }}>
          <div className="eyebrow">Расписание</div>
          {error ? (
            <div style={{ color: '#dc2626', fontSize: 13, marginTop: 8 }}>{error}</div>
          ) : slots === null ? (
            <div style={{ color: 'var(--ink-soft)', marginTop: 8 }}>Загрузка…</div>
          ) : upcoming.length === 0 ? (
            <div style={{ color: 'var(--ink-soft)', fontSize: 13, marginTop: 8 }}>
              Ближайших занятий нет. Если ждёшь занятие — напиши куратору.
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginTop: 12 }}>
              {upcoming.map((slot) => {
                const accessible = isLessonAccessible(slot)
                return (
                  <div
                    key={slot.id}
                    style={{
                      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                      padding: '12px 16px', borderRadius: 12,
                      background: accessible ? 'var(--mint-soft)' : 'var(--paper-2, #f9f8ff)',
                      border: accessible ? '2px solid var(--mint, #9FE8C7)' : '1px solid var(--paper-3, #e5e2f0)',
                    }}
                  >
                    <div>
                      <div style={{ fontWeight: 700, fontSize: 14 }}>{formatDateTime(slot.datetime)}</div>
                      <div style={{ fontSize: 12, color: 'var(--ink-soft)', marginTop: 2 }}>
                        {slot.durationMin} мин · {slot.type === 'trial' ? 'Пробный' : slot.type === 'makeup' ? 'Отработка' : 'Обычный урок'}
                      </div>
                    </div>
                    {slot.zoomLink ? (
                      <a
                        href={slot.zoomLink}
                        target="_blank"
                        rel="noreferrer"
                        className="kb-btn"
                        style={{
                          fontSize: 13, padding: '8px 16px', textDecoration: 'none',
                          background: accessible ? 'var(--mint-ink, #0C4E2E)' : 'var(--paper-3, #e5e2f0)',
                          color: accessible ? '#fff' : 'var(--ink-soft)',
                          opacity: accessible ? 1 : 0.6,
                          pointerEvents: accessible ? 'auto' : 'none',
                        }}
                      >
                        {accessible ? 'Войти на занятие →' : 'Откроется ближе ко времени'}
                      </a>
                    ) : (
                      <span style={{ fontSize: 12, color: 'var(--ink-soft)' }}>Ссылка скоро появится</span>
                    )}
                  </div>
                )
              })}
            </div>
          )}
        </div>

        {/* Виджет: уведомления */}
        {notifications.length > 0 && (
          <div className="kb-card" style={{ padding: 20, gridColumn: '1 / -1' }}>
            <div className="eyebrow">Уведомления</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 12 }}>
              {notifications.map((n) => (
                <div
                  key={n.id}
                  style={{
                    padding: '10px 14px', borderRadius: 10,
                    background: n.read ? 'transparent' : 'var(--violet-soft, #f0edff)',
                    borderLeft: n.read ? '3px solid var(--paper-3, #e5e2f0)' : '3px solid var(--violet, #6B5CE7)',
                  }}
                  onClick={() => {
                    if (n.read) return
                    void markNotificationRead(n.id)
                    setNotifications((prev) => prev.map((x) => x.id === n.id ? { ...x, read: true } : x))
                  }}
                >
                  <div style={{ fontWeight: 700, fontSize: 14 }}>{n.title}</div>
                  <div style={{ fontSize: 13, color: 'var(--ink-soft)', marginTop: 2 }}>{n.body}</div>
                  <div style={{ fontSize: 11, color: 'var(--ink-soft)', marginTop: 4 }}>
                    {new Date(n.createdAt).toLocaleString('ru-RU', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

      </div>
    </PlatformShell>
  )
}
